// @ts-nocheck -- deterministic release-only webpack configuration
import type { NextConfig } from "next";
const crypto = require("node:crypto");
const fs = require("node:fs");

class StableReleaseModuleIdsPlugin {
  apply(compiler) {
    compiler.hooks.compilation.tap("StableReleaseModuleIdsPlugin", (compilation) => {
      compilation.hooks.beforeModuleIds.tap("StableReleaseModuleIdsPlugin", (modules) => {
        const projectRoot = fs.realpathSync(process.cwd()).split("\\").join("/");
        const dependencyRoot = fs.realpathSync("node_modules").split("\\").join("/");
        const normalize = (value) => String(value ?? "")
          .split("\\").join("/")
          .split(projectRoot).join("<project>")
          .split(dependencyRoot).join("<node_modules>")
          .replace(/(?:file:\/\/)?[^!|\s]*\/source\/frontend/g, "<project>");
        const seen = new Set();
        for (const module of modules) {
          if (compilation.chunkGraph.getModuleId(module) !== null) continue;
          const stable = [
            module.constructor?.name,
            module.type,
            module.layer,
            normalize(module.identifier()),
          ].join("|");
          const id = crypto.createHash("sha256").update(stable).digest("hex").slice(0, 24);
          if (seen.has(id)) throw new Error("stable release module identity collision");
          seen.add(id);
          compilation.chunkGraph.setModuleId(module, id);
        }
      });
    });
  }
}

const nextConfig: NextConfig = {
  reactStrictMode: true,
  generateBuildId: async () => "spar-release-a743c59c719dd10db742",
  webpack: (config) => {
    config.optimization.moduleIds = false;
    config.optimization.chunkIds = "deterministic";
    config.optimization.concatenateModules = false;
    config.output.hashSalt = "spar-release-a743c59c719dd10db742";
    config.plugins.push(new StableReleaseModuleIdsPlugin());
    return config;
  },
};

export default nextConfig;
